import requests
import json

def _get_session():
    """Create a requests session with GitHub auth headers."""
    base_url = (GITHUB_API_URL or "https://api.github.com").rstrip("/")
    session = requests.Session()
    session.headers.update({
        "Authorization": f"token {GITHUB_TOKEN}",
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28"
    })
    return session, base_url

def list_repos(owner: str = "", repo_type: str = "all", sort: str = "updated", per_page: int = 30) -> str:
    """List GitHub repositories. If owner is empty, lists repos for the authenticated user. Otherwise lists repos for the specified user/org. repo_type can be: all, owner, public, private, member. sort can be: created, updated, pushed, full_name."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_session()
        params = {"per_page": per_page, "sort": sort}
        if owner:
            url = f"{base_url}/users/{owner}/repos"
            params["type"] = repo_type if repo_type in ["all", "owner", "member"] else "all"
        else:
            url = f"{base_url}/user/repos"
            params["type"] = repo_type
        resp = session.get(url, params=params, timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        repos = resp.json()
        if not repos:
            return "No repositories found."
        lines = []
        for r in repos:
            visibility = "private" if r.get("private") else "public"
            stars = r.get("stargazers_count", 0)
            lang = r.get("language", "N/A")
            desc = r.get("description") or "No description"
            lines.append(f"- **{r['full_name']}** ({visibility}, ⭐{stars}, {lang})\n  {desc}")
        return f"Found {len(repos)} repositories:\n\n" + "\n".join(lines)
    except Exception as e:
        return f"Error listing repos: {str(e)}"

def get_repo_details(owner: str, repo: str) -> str:
    """Get detailed information about a specific GitHub repository. Provide owner and repo name separately (e.g., owner='octocat', repo='Hello-World')."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_session()
        resp = session.get(f"{base_url}/repos/{owner}/{repo}", timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        r = resp.json()
        info = {
            "Full Name": r.get("full_name"),
            "Description": r.get("description") or "No description",
            "Visibility": "Private" if r.get("private") else "Public",
            "Default Branch": r.get("default_branch"),
            "Language": r.get("language") or "N/A",
            "Stars": r.get("stargazers_count", 0),
            "Forks": r.get("forks_count", 0),
            "Open Issues": r.get("open_issues_count", 0),
            "Created": r.get("created_at"),
            "Updated": r.get("updated_at"),
            "Clone URL (HTTPS)": r.get("clone_url"),
            "Homepage": r.get("homepage") or "N/A",
            "License": (r.get("license") or {}).get("name", "N/A"),
            "Archived": r.get("archived", False),
            "Topics": ", ".join(r.get("topics", [])) or "None"
        }
        lines = [f"**{k}:** {v}" for k, v in info.items()]
        return "\n".join(lines)
    except Exception as e:
        return f"Error getting repo details: {str(e)}"

def create_repo(name: str, description: str = "", private: bool = False, auto_init: bool = True) -> str:
    """Create a new GitHub repository for the authenticated user. name is required. Set private=True for a private repo. auto_init=True creates an initial README commit."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_session()
        payload = {
            "name": name,
            "description": description,
            "private": private,
            "auto_init": auto_init
        }
        resp = session.post(f"{base_url}/user/repos", json=payload, timeout=30)
        if resp.status_code not in [200, 201]:
            return f"Error ({resp.status_code}): {resp.text}"
        r = resp.json()
        save_link(r['html_url'], f"Repo: {r['full_name']}")
        return f"Repository created successfully!\n- **Name:** {r['full_name']}\n- **URL:** {r['html_url']}\n- **Visibility:** {'Private' if r.get('private') else 'Public'}\n- **Default Branch:** {r.get('default_branch', 'N/A')}"
    except Exception as e:
        return f"Error creating repo: {str(e)}"

import requests
import json

def _get_branch_session():
    """Create a requests session with GitHub auth headers."""
    base_url = (GITHUB_API_URL or "https://api.github.com").rstrip("/")
    session = requests.Session()
    session.headers.update({
        "Authorization": f"token {GITHUB_TOKEN}",
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28"
    })
    return session, base_url

def list_branches(owner: str, repo: str, per_page: int = 30) -> str:
    """List branches in a GitHub repository. Provide owner and repo name (e.g., owner='octocat', repo='Hello-World')."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_branch_session()
        resp = session.get(f"{base_url}/repos/{owner}/{repo}/branches", params={"per_page": per_page}, timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        branches = resp.json()
        if not branches:
            return f"No branches found in {owner}/{repo}."
        lines = []
        for b in branches:
            protected = " 🔒" if b.get("protected") else ""
            sha_short = b.get("commit", {}).get("sha", "")[:7]
            lines.append(f"- **{b['name']}**{protected} (latest: {sha_short})")
        return f"Branches in {owner}/{repo} ({len(branches)}):\n\n" + "\n".join(lines)
    except Exception as e:
        return f"Error listing branches: {str(e)}"

def create_branch(owner: str, repo: str, new_branch: str, source_branch: str = "main") -> str:
    """Create a new branch in a GitHub repository. Provide owner, repo, the new branch name, and optionally the source branch to branch from (defaults to 'main')."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_branch_session()
        # Get the SHA of the source branch
        ref_resp = session.get(f"{base_url}/repos/{owner}/{repo}/git/ref/heads/{source_branch}", timeout=30)
        if ref_resp.status_code != 200:
            return f"Error getting source branch '{source_branch}' ({ref_resp.status_code}): {ref_resp.text}"
        sha = ref_resp.json()["object"]["sha"]
        # Create the new branch
        payload = {
            "ref": f"refs/heads/{new_branch}",
            "sha": sha
        }
        resp = session.post(f"{base_url}/repos/{owner}/{repo}/git/refs", json=payload, timeout=30)
        if resp.status_code not in [200, 201]:
            return f"Error creating branch ({resp.status_code}): {resp.text}"
        return f"Branch **{new_branch}** created successfully in {owner}/{repo} from **{source_branch}** (SHA: {sha[:7]})."
    except Exception as e:
        return f"Error creating branch: {str(e)}"

