def fork_repo(owner: str, repo: str, organization: str = "") -> str:
    """Fork a GitHub repository. Forks to the authenticated user's account by default. Provide organization name to fork to an org instead."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_fork_session()
        payload = {}
        if organization:
            payload["organization"] = organization
        resp = session.post(f"{base_url}/repos/{owner}/{repo}/forks", json=payload, timeout=30)
        if resp.status_code not in [200, 201, 202]:
            return f"Error ({resp.status_code}): {resp.text}"
        r = resp.json()
        save_link(r['html_url'], f"Fork: {r['full_name']}")
        return f"Repository forked successfully!\n- **Fork:** {r['full_name']}\n- **URL:** {r['html_url']}\n- **Parent:** {owner}/{repo}"
    except Exception as e:
        return f"Error forking repo: {str(e)}"

def list_forks(owner: str, repo: str, sort: str = "newest", per_page: int = 30) -> str:
    """List forks of a GitHub repository. sort can be: newest, oldest, stargazers, watchers."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_fork_session()
        resp = session.get(f"{base_url}/repos/{owner}/{repo}/forks", params={"sort": sort, "per_page": per_page}, timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        forks = resp.json()
        if not forks:
            return f"No forks found for {owner}/{repo}."
        lines = []
        for f in forks:
            lines.append(f"- **{f['full_name']}** (⭐{f.get('stargazers_count', 0)}, updated: {f.get('updated_at', 'N/A')})")
        return f"Forks of {owner}/{repo} ({len(forks)}):\n\n" + "\n".join(lines)
    except Exception as e:
        return f"Error listing forks: {str(e)}"

import requests
import json

def _get_pr_session():
    """Create a requests session with GitHub auth headers."""
    base_url = (GITHUB_API_URL or "https://api.github.com").rstrip("/")
    session = requests.Session()
    session.headers.update({
        "Authorization": f"token {GITHUB_TOKEN}",
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28"
    })
    return session, base_url

def list_pull_requests(owner: str, repo: str, state: str = "open", per_page: int = 30) -> str:
    """List pull requests in a GitHub repository. state can be: open, closed, all."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_pr_session()
        resp = session.get(f"{base_url}/repos/{owner}/{repo}/pulls", params={"state": state, "per_page": per_page}, timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        prs = resp.json()
        if not prs:
            return f"No {state} pull requests found in {owner}/{repo}."
        lines = []
        for pr in prs:
            user = pr.get("user", {}).get("login", "unknown")
            labels = ", ".join([l["name"] for l in pr.get("labels", [])]) or "none"
            lines.append(f"- **#{pr['number']}** {pr['title']}\n  By: {user} | State: {pr['state']} | Labels: {labels}\n  {pr['head']['label']} → {pr['base']['label']}")
        return f"Pull Requests in {owner}/{repo} ({state}, {len(prs)}):\n\n" + "\n".join(lines)
    except Exception as e:
        return f"Error listing PRs: {str(e)}"

def get_pull_request_details(owner: str, repo: str, pr_number: int) -> str:
    """Get detailed information about a specific pull request. Provide owner, repo, and PR number."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_pr_session()
        resp = session.get(f"{base_url}/repos/{owner}/{repo}/pulls/{pr_number}", timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        pr = resp.json()
        info = {
            "Title": pr.get("title"),
            "Number": f"#{pr.get('number')}",
            "State": pr.get("state"),
            "Author": pr.get("user", {}).get("login", "unknown"),
            "Branch": f"{pr['head']['label']} → {pr['base']['label']}",
            "Created": pr.get("created_at"),
            "Updated": pr.get("updated_at"),
            "Merged": pr.get("merged_at") or "Not merged",
            "Mergeable": str(pr.get("mergeable", "unknown")),
            "Commits": pr.get("commits", 0),
            "Additions": pr.get("additions", 0),
            "Deletions": pr.get("deletions", 0),
            "Changed Files": pr.get("changed_files", 0),
            "Labels": ", ".join([l["name"] for l in pr.get("labels", [])]) or "None",
            "Reviewers": ", ".join([r["login"] for r in pr.get("requested_reviewers", [])]) or "None",
            "URL": pr.get("html_url")
        }
        lines = [f"**{k}:** {v}" for k, v in info.items()]
        body = pr.get("body") or "No description"
        lines.append(f"\n**Description:**\n{body[:1000]}")
        return "\n".join(lines)
    except Exception as e:
        return f"Error getting PR details: {str(e)}"

def create_pull_request(owner: str, repo: str, title: str, head: str, base: str = "main", body: str = "", draft: bool = False) -> str:
    """Create a new pull request. Provide owner, repo, title, head branch (source), base branch (target, defaults to 'main'), and optional body/description. Set draft=True for a draft PR."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_pr_session()
        payload = {
            "title": title,
            "head": head,
            "base": base,
            "body": body,
            "draft": draft
        }
        resp = session.post(f"{base_url}/repos/{owner}/{repo}/pulls", json=payload, timeout=30)
        if resp.status_code not in [200, 201]:
            return f"Error ({resp.status_code}): {resp.text}"
        pr = resp.json()
        save_link(pr['html_url'], f"PR #{pr['number']}: {pr['title']}")
        return f"Pull request created successfully!\n- **#{pr['number']}** {pr['title']}\n- **Branch:** {head} → {base}\n- **URL:** {pr['html_url']}\n- **Draft:** {draft}"
    except Exception as e:
        return f"Error creating PR: {str(e)}"

def merge_pull_request(owner: str, repo: str, pr_number: int, merge_method: str = "merge", commit_title: str = "") -> str:
    """Merge a pull request. merge_method can be: merge, squash, rebase. Optionally provide a custom commit_title."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_pr_session()
        payload = {"merge_method": merge_method}
        if commit_title:
            payload["commit_title"] = commit_title
        resp = session.put(f"{base_url}/repos/{owner}/{repo}/pulls/{pr_number}/merge", json=payload, timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        r = resp.json()
        if r.get("merged"):
            return f"Pull request #{pr_number} merged successfully!\n- **SHA:** {r.get('sha', 'N/A')}\n- **Message:** {r.get('message', 'Merged')}"
        else:
            return f"Pull request #{pr_number} could not be merged: {r.get('message', 'Unknown reason')}"
    except Exception as e:
        return f"Error merging PR: {str(e)}"

import requests
import json

def _get_issue_session():
    """Create a requests session with GitHub auth headers."""
    base_url = (GITHUB_API_URL or "https://api.github.com").rstrip("/")
    session = requests.Session()
    session.headers.update({
        "Authorization": f"token {GITHUB_TOKEN}",
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28"
    })
    return session, base_url

def list_issues(owner: str, repo: str, state: str = "open", labels: str = "", per_page: int = 30) -> str:
    """List issues in a GitHub repository. state can be: open, closed, all. Optionally filter by comma-separated labels."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_issue_session()
        params = {"state": state, "per_page": per_page}
        if labels:
            params["labels"] = labels
        resp = session.get(f"{base_url}/repos/{owner}/{repo}/issues", params=params, timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        issues = resp.json()
        # Filter out pull requests (GitHub API returns PRs as issues too)
        issues = [i for i in issues if "pull_request" not in i]
        if not issues:
            return f"No {state} issues found in {owner}/{repo}."
        lines = []
        for issue in issues:
            user = issue.get("user", {}).get("login", "unknown")
            issue_labels = ", ".join([l["name"] for l in issue.get("labels", [])]) or "none"
            assignees = ", ".join([a["login"] for a in issue.get("assignees", [])]) or "unassigned"
            lines.append(f"- **#{issue['number']}** {issue['title']}\n  By: {user} | Labels: {issue_labels} | Assigned: {assignees}")
        return f"Issues in {owner}/{repo} ({state}, {len(issues)}):\n\n" + "\n".join(lines)
    except Exception as e:
        return f"Error listing issues: {str(e)}"

def get_issue_details(owner: str, repo: str, issue_number: int) -> str:
    """Get detailed information about a specific issue. Provide owner, repo, and issue number."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_issue_session()
        resp = session.get(f"{base_url}/repos/{owner}/{repo}/issues/{issue_number}", timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        issue = resp.json()
        info = {
            "Title": issue.get("title"),
            "Number": f"#{issue.get('number')}",
            "State": issue.get("state"),
            "Author": issue.get("user", {}).get("login", "unknown"),
            "Created": issue.get("created_at"),
            "Updated": issue.get("updated_at"),
            "Closed": issue.get("closed_at") or "Open",
            "Labels": ", ".join([l["name"] for l in issue.get("labels", [])]) or "None",
            "Assignees": ", ".join([a["login"] for a in issue.get("assignees", [])]) or "Unassigned",
            "Milestone": (issue.get("milestone") or {}).get("title", "None"),
            "Comments": issue.get("comments", 0),
            "URL": issue.get("html_url")
        }
        lines = [f"**{k}:** {v}" for k, v in info.items()]
        body = issue.get("body") or "No description"
        lines.append(f"\n**Description:**\n{body[:1500]}")
        return "\n".join(lines)
    except Exception as e:
        return f"Error getting issue details: {str(e)}"

def create_issue(owner: str, repo: str, title: str, body: str = "", labels: str = "", assignees: str = "") -> str:
    """Create a new issue in a GitHub repository. Provide owner, repo, title. Optionally provide body, comma-separated labels, and comma-separated assignees."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_issue_session()
        payload = {"title": title}
        if body:
            payload["body"] = body
        if labels:
            payload["labels"] = [l.strip() for l in labels.split(",") if l.strip()]
        if assignees:
            payload["assignees"] = [a.strip() for a in assignees.split(",") if a.strip()]
        resp = session.post(f"{base_url}/repos/{owner}/{repo}/issues", json=payload, timeout=30)
        if resp.status_code not in [200, 201]:
            return f"Error ({resp.status_code}): {resp.text}"
        issue = resp.json()
        save_link(issue['html_url'], f"Issue #{issue['number']}: {issue['title']}")
        return f"Issue created successfully!\n- **#{issue['number']}** {issue['title']}\n- **URL:** {issue['html_url']}"
    except Exception as e:
        return f"Error creating issue: {str(e)}"

import requests
import json

def _get_commit_session():
    """Create a requests session with GitHub auth headers."""
    base_url = (GITHUB_API_URL or "https://api.github.com").rstrip("/")
    session = requests.Session()
    session.headers.update({
        "Authorization": f"token {GITHUB_TOKEN}",
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28"
    })
    return session, base_url

def list_commits(owner: str, repo: str, branch: str = "", per_page: int = 20) -> str:
    """List recent commits in a GitHub repository. Optionally specify a branch name (defaults to the repo's default branch)."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_commit_session()
        params = {"per_page": per_page}
        if branch:
            params["sha"] = branch
        resp = session.get(f"{base_url}/repos/{owner}/{repo}/commits", params=params, timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        commits = resp.json()
        if not commits:
            return f"No commits found in {owner}/{repo}."
        lines = []
        for c in commits:
            sha = c.get("sha", "")[:7]
            msg = c.get("commit", {}).get("message", "").split("\n")[0][:80]
            author = c.get("commit", {}).get("author", {}).get("name", "unknown")
            date = c.get("commit", {}).get("author", {}).get("date", "")
            lines.append(f"- **{sha}** {msg}\n  By: {author} | {date}")
        branch_info = f" on branch '{branch}'" if branch else ""
        return f"Recent commits in {owner}/{repo}{branch_info} ({len(commits)}):\n\n" + "\n".join(lines)
    except Exception as e:
        return f"Error listing commits: {str(e)}"

def get_authenticated_user() -> str:
    """Get information about the currently authenticated GitHub user. Useful for checking token validity and seeing who is logged in."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_commit_session()
        resp = session.get(f"{base_url}/user", timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}. Check that your GITHUB_TOKEN is valid."
        user = resp.json()
        info = {
            "Username": user.get("login"),
            "Name": user.get("name") or "N/A",
            "Email": user.get("email") or "N/A",
            "Bio": user.get("bio") or "N/A",
            "Public Repos": user.get("public_repos", 0),
            "Private Repos": user.get("total_private_repos", 0),
            "Followers": user.get("followers", 0),
            "Following": user.get("following", 0),
            "Created": user.get("created_at"),
            "Profile URL": user.get("html_url")
        }
        lines = [f"**{k}:** {v}" for k, v in info.items()]
        return "Authenticated User:\n\n" + "\n".join(lines)
    except Exception as e:
        return f"Error getting user info: {str(e)}"

def check_repo_permission(owner: str, repo: str, username: str) -> str:
    """Check a user's permission level for a repository. Returns: admin, write, read, or none."""
    if not GITHUB_TOKEN:
        return "Error: GITHUB_TOKEN must be configured in Environment Variables."
    try:
        session, base_url = _get_commit_session()
        resp = session.get(f"{base_url}/repos/{owner}/{repo}/collaborators/{username}/permission", timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"
        data = resp.json()
        perm = data.get("permission", "unknown")
        role = data.get("role_name", "unknown")
        return f"User **{username}** has **{perm}** permission (role: {role}) on {owner}/{repo}."
    except Exception as e:
        return f"Error checking permissions: {str(e)}"
